// // This module implements a 8-bit counter that decrements by 1 on each positive clock edge when the enable signal is high. If the reset signal is high, the counter should reset to 0 on the next clock edge.
module counter_with_enable(
    input               clk,
    input               rst,
    input               enable,

    output reg [7:0]    count
);

always@(posedge clk) begin
    if (rst)
        count <= 8'b00000000;
    else if (enable)
        count <= count + 1;
end

endmodule
